import json, subprocess
def probe(file_path):
    r = subprocess.run(['ffprobe', '-v', 'error', '-show_format', '-show_streams', '-of', 'json', file_path], capture_output=True, text=True, timeout=30)
    if r.returncode != 0: return {'error': r.stderr}
    return json.loads(r.stdout)

import subprocess
def transcode(inp, out, codec='libx264', acodec='aac', crf=23):
    cmd = ['ffmpeg', '-y', '-i', inp, '-c:v', codec, '-crf', str(crf), '-c:a', acodec, out]
    r = subprocess.run(cmd, capture_output=True, text=True, timeout=3600)
    return {'success': r.returncode == 0, 'stderr': r.stderr[-500:]}

import subprocess
def trim(inp, out, start, dur):
    r = subprocess.run(['ffmpeg', '-y', '-ss', start, '-i', inp, '-t', dur, '-c', 'copy', out], capture_output=True, text=True, timeout=3600)
    return {'success': r.returncode == 0, 'stderr': r.stderr[-500:]}

import subprocess
def extract_audio(inp, out, fmt='mp3', br='192k'):
    r = subprocess.run(['ffmpeg', '-y', '-i', inp, '-vn', '-acodec', 'libmp3lame' if fmt == 'mp3' else fmt, '-ab', br, out], capture_output=True, text=True, timeout=3600)
    return {'success': r.returncode == 0, 'stderr': r.stderr[-500:]}

import subprocess
def thumb(inp, out, ts='00:00:01'):
    r = subprocess.run(['ffmpeg', '-y', '-ss', ts, '-i', inp, '-vframes', '1', '-q:v', '2', out], capture_output=True, text=True, timeout=60)
    return {'success': r.returncode == 0, 'stderr': r.stderr[-500:]}

import os,json
p=json.loads(os.environ.get('__EXECUTOR_INPUT__','{}'))
root=p.get('path','.')
stats={'files':0,'lines':0,'todos':0,'functions':0}
for dp,dn,fn in os.walk(root):
 if '.git' in dp or 'target' in dp or 'node_modules' in dp:continue
 for f in fn:
  if f.endswith(('.py','.rs','.js','.ts')):
   stats['files']+=1
   try:
    for line in open(os.path.join(dp,f)):
     stats['lines']+=1
     if 'TODO' in line or 'FIXME' in line:stats['todos']+=1
     if line.strip().startswith(('def ','fn ','function ')):stats['functions']+=1
   except:pass
print(json.dumps(stats,ensure_ascii=False))

import subprocess,json,os
p=json.loads(os.environ.get('__EXECUTOR_INPUT__','{}'))
path=p.get('path','.')
result={'success':True}
cargo=os.path.join(path,'Cargo.toml')
if os.path.exists(cargo):
 result['has_cargo']=True
 result['cargo_toml']=open(cargo).read()[:300]
 try:
  r=subprocess.run(['cargo','check','--message-format=short'],cwd=path,capture_output=True,text=True,timeout=30)
  result['check_exit']=r.returncode
  result['check_stderr']=r.stderr[-200:]
 except subprocess.TimeoutExpired:
  result['check_exit']='timeout'
 except Exception as e:
  result['check_error']=str(e)
else:
 result['has_cargo']=False
 result['message']='no Cargo.toml found'
print(json.dumps(result,ensure_ascii=False))
